class Geofence { final String geofenceId; final String label; final double latitude; final double longitude; final double radiusMeters; final bool isActive; const Geofence({required this.geofenceId, required this.label, required this.latitude, required this.longitude, required this.radiusMeters, this.isActive = true}); bool containsPoint(double lat, double lng) { const double earthRadius = 6371000; final dLat = (lat - latitude) * 3.141592653589793 / 180; final dLng = (lng - longitude) * 3.141592653589793 / 180; final a = dLat * dLat; final distance = earthRadius * (2 * a); return distance <= radiusMeters; } }